g_taskUserFormPreferences = {};
var tasker_User_Form_Preferences = Class.create();
tasker_User_Form_Preferences.prototype = {
    initialize: function() {
		// STRY0116257
		this.tsss = new tasking_System_Settings_Scripts();
		this._formViewsEnabled = this.tsss.getTaskerTaskFormViewsEnabled();
		// STRY0119569 - this constant is in tasker_User_Form_Preferences
		this.PREFERENCE_DEFAULT_TASK_FORM_VIEW = 'DTechApps.Tasker.' + '.defaultTaskFormView';

		// DFCT0010755
		this.g_taskUserFormPreferences = g_taskUserFormPreferences;
		if (this.g_taskUserFormPreferences.lastRefreshDateTime != undefined){
			var preferencesUpdated = this._getPreferencesUpdated();
			if(!preferencesUpdated){
				// if records exist and the last time preferences were loaded is later than the last update, then return.
				// no need to reload the preferences as they haven't changed
				return this.g_taskUserFormPreferences;						
			}
		}
		// set the global object
		this.g_taskUserFormPreferences = this._loadFormPreferences();
		g_taskUserFormPreferences = this.g_taskUserFormPreferences;		
		return this.g_taskUserFormPreferences;
    },

	loadFormViews: function(view_type){
		var taskFormViews = [];
		// STRY0116257 - if the viewtype is disabled, return empty list
		if(this._formViewsEnabled.contains(view_type)){
			var taskFormView;
			var gr_task_form_views = new GlideRecordSecure("x_153465_discovert_tasker_form_views");
			gr_task_form_views.addQuery("u_active", true);
			gr_task_form_views.addQuery("u_view_type", view_type);
			gr_task_form_views.orderBy("u_order");
			gr_task_form_views.query();
			while(gr_task_form_views.next()){
				taskFormView = this._loadFormViewObject(gr_task_form_views);
				taskFormViews.push(taskFormView);
			}
		}
		return taskFormViews;
	},

	// INPUT: Task record or null
	// RETURN the Form View object for the task.  If no task, return user default, if no user default saved yet, return system default
	getDefaultTaskerFormView: function(gr_task){
		var defaultFormViewId;
		var taskFormView;
		if(gr_task && gr_task.u_servicenow_form_view) {
			defaultFormViewId = gr_task.u_servicenow_form_view;
		} else {
			var defaultTaskFormView = gs.getUser().getPreference(this.PREFERENCE_DEFAULT_TASK_FORM_VIEW);
			if(defaultTaskFormView){
				defaultFormViewId = defaultTaskFormView;
			} else {
				defaultFormViewId = this.tsss.getTaskerDefaultView();
			}
		}
		taskFormView = this._getDefaultFormViewUsingId(defaultFormViewId);
		return taskFormView;
	},

	// Object Returned 
	//    taskFormView = {sys_id: "", icon:"", description:"", title:"", sn_view: "", view_type: "", filter: "", fieldValues: []};
	// NOTE: if no form views for a task type, then this will return an undefined object
	_getDefaultFormViewUsingId: function(tfv_sys_id){
		var taskFormView;
		var gr_task_form_views = new GlideRecordSecure("x_153465_discovert_tasker_form_views");
		if(gr_task_form_views.get(tfv_sys_id)){
			taskFormView = this._loadFormViewObject(gr_task_form_views);
		} else {
			// technically this should not be necessary, but since an early 2.8 push stored object instead of id
			// if the sys_id isn't found, reset to the system default
			var defaultFormViewId = this.tsss.getTaskerDefaultView();
			if(tfv_sys_id != defaultFormViewId){
				if(gr_task_form_views.get(defaultFormViewId)){
					taskFormView = this._loadFormViewObject(gr_task_form_views);
				}
			}
		}
		return taskFormView;
	},

	// DFCT0011036 - was incorrectly only looking for tasker type
	getDefaultFormViewForTaskTypeAndFormViewType: function (tasker_type, form_view_type){
		var taskFormView;
		var gr_task_form_views = new GlideRecordSecure("x_153465_discovert_tasker_form_views");
		// look for both sys_id and name for the type
		gr_task_form_views.addQuery("u_view_type", form_view_type);
		// quick view uses task type and form viwe type to load the right view
		if(form_view_type == "quick_view"){
			// STRY0127550 add value to the list of things to try to find
			gr_task_form_views.addQuery("u_tasker_type", tasker_type).addOrCondition("u_tasker_type.tasker_type", tasker_type).addOrCondition("u_tasker_type.u_value", tasker_type);
		}
		gr_task_form_views.orderBy("u_order");
		gr_task_form_views.query();

		if(gr_task_form_views.next()){
			taskFormView = this._loadFormViewObject(gr_task_form_views);
		}
		return taskFormView;		
	},

	// INPUT: Tasker Type value, View Type value
	// RETURN the lowest order Form View object 
	// Object Returned - 
	//    taskFormView = {sys_id: "", icon:"", description:"", title:"", sn_view: "", view_type: "", filter: "", fieldValues: []};
	// NOTE: if no form views for a task type, then this will return an undefined object
	getDefaultFormViewForTaskType: function(taskerTypeValue, viewType){
		var taskFormView;
		var gr_task_form_views = new GlideRecordSecure("x_153465_discovert_tasker_form_views");
		// look for both sys_id and name for the type
		// STRY0127550 add value to the list of things to try to find
		gr_task_form_views.addQuery("u_tasker_type", taskerTypeValue).addOrCondition("u_tasker_type.tasker_type", taskerTypeValue).addOrCondition("u_tasker_type.u_value", taskerTypeValue);
		gr_task_form_views.orderBy("u_order");
		gr_task_form_views.query();

		if(gr_task_form_views.next()){
			taskFormView = this._loadFormViewObject(gr_task_form_views);
		}
		return taskFormView;
	},

	// loads a form view object from the form view record
	// Object Returned
	//    taskFormView = {sys_id: "", icon:"", description:"", title:"", sn_view: "", view_type: "", filter: "", fieldValues: []};
	_loadFormViewObject: function(gr_task_form_views){
		var taskFormView = {sys_id: "", icon:"", description:"", title:"", sn_view: "", view_type: "", filter: "", fieldValues: []};
		var fieldValues = [];
		var filter = gr_task_form_views.getValue("u_form_filter");
		var arrfields = filter.split('^');
		for (var i = 0; i < arrfields.length; i++){
			var arrfieldValuePair = arrfields[i].split("=");
			if(arrfieldValuePair.length == 2){
				var fieldValuePair = {field:"", value:""};
				fieldValuePair.field = arrfieldValuePair[0].toString().trim();
				fieldValuePair.value = arrfieldValuePair[1].toString().trim();
				fieldValues.push(fieldValuePair);	
			}
		}
		taskFormView = {
			sys_id: gr_task_form_views.getUniqueValue(),
			icon:"", 
			description: gr_task_form_views.getDisplayValue("u_description"),
			view_type: gr_task_form_views.getValue("u_view_type"),
			title: gr_task_form_views.getDisplayValue("u_display_name"),
			sn_view: gr_task_form_views.getDisplayValue("u_servicenow_form_view"),
			filter: gr_task_form_views.getValue("u_form_filter"),
			fieldValues: fieldValues
		};
		return taskFormView;
	},
	// Get last updated time
	_getPreferencesUpdated: function(){
		// DFCT0010755 
		var lastUpdated = false;
		var gr_user_preferences = new GlideRecord('x_153465_discovert_task_form_preferences');
		var gdt = new GlideDateTime();
		gdt.setValue(this.g_taskUserFormPreferences.lastRefreshDateTime);
		gr_user_preferences.addQuery('sys_updated_on', '>', gdt);
		gr_user_preferences.query();
		if(gr_user_preferences.next())
			lastUpdated = true;
		return lastUpdated;
	},

	_loadFormPreferences: function (){
		var taskUserFormPreferences = {};
		taskUserFormPreferences.Preferences = [];
		// TODO - Load the list of Form preferences for the user, OU and Top OU
		var gr_user_preferences = new GlideRecord('x_153465_discovert_task_form_preferences');
		gr_user_preferences.addQuery('u_active', true);
		// put the highest order first as they take precedence
		gr_user_preferences.orderByDesc('u_order');
		gr_user_preferences.query();
		var fields = gr_user_preferences.getElements();

		while(gr_user_preferences.next()){
			var userPrefernce = {};
			for (var i = 0; i < fields.length; i++) {
				var glideElement = fields[i];
				var key = glideElement.getName();
				if(!key.startsWith('sys_')){
					userPrefernce[key] = {};
					// set the display value the same way reguardless of field
					userPrefernce[key].displayValue = gr_user_preferences.getDisplayValue(glideElement.getName());

					switch (key){
						case 'u_related_table_view':
							// lookup the view (used in URL)
							userPrefernce[key].value = gr_user_preferences.getElement('u_related_table_view').getRefRecord('sys_ui_form').getElement('view').getRefRecord('sys_ui_view').getValue('name');
							break;
						case 'u_related_table':
							// lookup the table name (used in URL)
							userPrefernce[key].value = gr_user_preferences.getValue(glideElement.getName());
							break;
						case 'u_service_portal':
							// lookup the service portal url_suffix (used in URL)
							userPrefernce[key].value = gr_user_preferences.getElement('u_service_portal').getRefRecord('sp_portal').getValue('url_suffix');
							break;
						case 'u_servicenow_form_view':
							// lookup the service from view (used in URL)
							userPrefernce[key].value = 
								gr_user_preferences.getElement('u_servicenow_form_view').getRefRecord('sys_ui_form').getElement('view').getRefRecord('sys_ui_view').getValue('name');
							break;
						case 'u_servicenow_portal_page':
							// lookup the page id (used in URL)
							userPrefernce[key].value = 
								gr_user_preferences.getElement('u_servicenow_portal_page').getRefRecord('sp_page').getValue('id');
							break;
						default:
							userPrefernce[key].value = gr_user_preferences.getValue(glideElement.getName());							
							break;
					}
				}
			}
			taskUserFormPreferences.Preferences.push(userPrefernce);
		}	
		var dteLastRefresh = new GlideDateTime();
		// DFCT0010755
		taskUserFormPreferences.lastRefreshDateTime = dteLastRefresh.getValue();

		// STRY0113838
		taskUserFormPreferences.defaultServicePortal = this._getDefaultServicePortalSuffix();
		return taskUserFormPreferences;
	},

	_getDefaultServicePortalSuffix: function(){
		var gr_sp_portal = new GlideRecord('sp_portal');
		// DFCT0010933
		// gr_sp_portal.addQuery('default', 'true');
		gr_sp_portal.addQuery('sys_scope', 'c6b1162d4fc10300303dc3818110c7b1');

		gr_sp_portal.query();
		if (gr_sp_portal.next()) {
			return gr_sp_portal.getValue('url_suffix');
		}		
	},

	loadMyFormPreferences: function (OUsWhereIamAMember, OUsWhereIamATaskManager, UserTopOUs){
		// STRY0114645 
		var userID = gs.getUserID();

		// if user's OUs are not passed in, load them
		// USE this for all loadMy - because it uses session variable to avoid loading
		if(!OUsWhereIamAMember)
			OUsWhereIamAMember = this.tsss.getOUsWhereIamAMember();

		if (!OUsWhereIamATaskManager) {
			OUsWhereIamATaskManager = this.tsss.getMyOUTaskManagers();
		}

		// STRY0114645 
		if (!UserTopOUs) {
			UserTopOUs = this.tsss.getTopOUsForUser(OUsWhereIamAMember);
		}

		// DFCT0010708 - STRY0114645 
		return this._userFormPreferences(userID, OUsWhereIamAMember, OUsWhereIamATaskManager, UserTopOUs);
	},

	// DFCT0010708
	loadUserFormPreferences: function (userID){
		var OUsWhereUserIsAMember = this.tsss.getOUsWhereUserIsAMember(userID);
		var OUsWhereUserIsTaskManager = this.tsss.getUserOUTaskManagers(userID);
		// STRY0114645 
		var UserTopOUs = this.tsss.getTopOUsForUser(OUsWhereUserIsAMember);
		// STRY0114645 
		return this._userFormPreferences(userID, OUsWhereUserIsAMember, OUsWhereUserIsTaskManager, UserTopOUs);
	},

	// DFCT0010708
	_userFormPreferences: function (userID, OUsWhereUserIsAMember, OUsWhereUserIsTaskManager, UserTopOUs){
		var userInfo = new x_153465_discovert.UserInfoScripts();
		var isAdministrator = userInfo.UserHasRoleScoped('x_153465_discovert.tasker_global_Tasking_Authority_member_admin', userID);
		var isTaskExecutive = userInfo.UserHasRoleScoped('x_153465_discovert.Task_Executive', userID);
		var isTaskManager = (OUsWhereUserIsTaskManager.length > 0);

		// STRY0114645 
		// TODO - ADD TASK CHECKS for Hierarchy
		// load global preferences, things that apply to all users
		var userPreferences = this.g_taskUserFormPreferences.Preferences.filter(function (pref){
			var matchFailure = 
				(pref.u_task_user.displayValue != '' && pref.u_task_user.displayValue != null && pref.u_task_user.value != userID) || 
				((pref.u_user_in_ou.displayValue != '' && pref.u_user_in_ou.displayValue != null)  && (OUsWhereUserIsAMember.indexOf(pref.u_user_in_ou.value)<0)) ||
				((pref.u_user_in_top_ou.displayValue != '' && pref.u_user_in_top_ou.displayValue != null)  && (UserTopOUs.indexOf(pref.u_user_in_top_ou.value)<0)) ||
				(pref.u_user_in_role.value == 'task_manager' && isTaskManager != true)  ||
				(pref.u_user_in_role.value == 'task_administrator' && isAdministrator != true) ||
				(pref.u_user_in_role.value == 'task_executive' && isTaskExecutive != true);
			if(!matchFailure){
				return pref;
			}
		});
		return userPreferences;
	},

	// DFCT0010708
	get_URL_Properties_for_Task_and_User_Based_on_Prefrences: function (userID, sys_id, current_view){
		// set defaults
		var url_Properties = {};
		var page_id;
		// STRY0126152  
		var userDefaultTaskPage = new TaskerWidgetIconsAndMessages("null").getPreferenceTaskDefaultPageId();
		// STRY0114645
		var system_default_page = gs.getProperty("x_153465_discovert.default_task_page") + '';
		// STRY0126152  
		if(userDefaultTaskPage){
			page_id = userDefaultTaskPage;
		} else if(system_default_page && system_default_page != ""){
			page_id = system_default_page;
		} else {
			page_id = 'simple_task';
		}
		url_Properties.pageId = page_id;
		url_Properties.pageTable = 'x_153465_discovert_route_task_instance';

		// DFCT0011870 - Task Form Preferences is NOT following "User in Top OU" field
		var OUsWhereUserIsAMember = this.tsss.getOUsWhereUserIsAMember(userID);
		var OUsWhereUserIsTaskManager = this.tsss.getUserOUTaskManagers(userID);
		// STRY0114645 
		var UserTopOUs = this.tsss.getTopOUsForUser(OUsWhereUserIsAMember);
		var userInfo = new x_153465_discovert.UserInfoScripts();
		var isAdministrator = userInfo.UserHasRoleScoped('x_153465_discovert.tasker_global_Tasking_Authority_member_admin', userID);
		var isTaskExecutive = userInfo.UserHasRoleScoped('x_153465_discovert.Task_Executive', userID);
		var isTaskManager = (OUsWhereUserIsTaskManager.length > 0);

		// STRY0114645
		var obj_system_default_view = this.getDefaultTaskerFormView();
		var system_default_view = obj_system_default_view.sn_view;
		// if view passed, use it, if not, use system property if set, otherwise, set to simple_task
		url_Properties.view =  current_view != '' ? current_view :
					system_default_view != '' ? system_default_view :'simple_task';

		url_Properties.portal_url_ref = this.g_taskUserFormPreferences.defaultServicePortal;
		var gr_task_pref = new GlideRecord(url_Properties.pageTable);
		if(gr_task_pref.get(sys_id)){
			var task_default_form_view = this.getDefaultTaskerFormView(gr_task_pref);
			var getFormToLoadOptions = this.g_taskUserFormPreferences.Preferences.filter(function (pref){
				// DFCT0011870 - Task Form Preferences is NOT following "User in Top OU" field
				var matchFailure = 
					(pref.u_task_user.displayValue != '' && pref.u_task_user.displayValue != null && pref.u_task_user.value.toString().indexOf(userID)==-1) || 
					((pref.u_user_in_ou.displayValue != '' && pref.u_user_in_ou.displayValue != null)  && (OUsWhereUserIsAMember.indexOf(pref.u_user_in_ou.value)<0)) ||
					((pref.u_user_in_top_ou.displayValue != '' && pref.u_user_in_top_ou.displayValue != null)  && (UserTopOUs.indexOf(pref.u_user_in_top_ou.value)<0)) ||
					(pref.u_user_in_role.value == 'task_manager' && isTaskManager != true)  ||
					(pref.u_user_in_role.value == 'task_administrator' && isAdministrator != true) ||
					(pref.u_user_in_role.value == 'task_executive' && isTaskExecutive != true) ||
					(pref.u_task_category.displayValue != '' && pref.u_task_category.displayValue != null  && pref.u_task_category.value.toString().indexOf(gr_task_pref.getValue('category'))==-1) ||
					(pref.u_tasker_sub_category.displayValue != '' && pref.u_tasker_sub_category.displayValue != null  && pref.u_tasker_sub_category.value.toString().indexOf(gr_task_pref.getValue('sub_category'))==-1) || 
					(pref.u_task_state.displayValue != '' && pref.u_task_state.displayValue != null  && pref.u_task_state.displayValue.toString().indexOf(gr_task_pref.getDisplayValue('state'))==-1) ||
					(pref.u_task_task_type.displayValue != '' && pref.u_task_task_type.displayValue != null  && pref.u_task_task_type.value.toString().indexOf(gr_task_pref.getValue('tasker_type'))==-1);
				if(!matchFailure){
					return pref;
				}
			});
			// If a match was found for this task, then use first item as 
			// form preferences were loaded in order by the ORDER 
			// to override the default settings
			if(getFormToLoadOptions.length > 0){
				var formToLoad = getFormToLoadOptions[0];
				if(formToLoad.u_servicenow_portal_page.displayValue != '' && formToLoad.u_servicenow_portal_page.displayValue != null){
					url_Properties.pageId = formToLoad.u_servicenow_portal_page.value;	
				}

				// form view is different for now pages are still loaded from the Form preference override, but form views are loaded from the task record
				// This will change as the page will move into the form view table and we will load the page from the task reference also
				// this will work much better as it will be set on creation, not set using the current override.
				// DFCT0011862 - determine what form settings exist, if a view override is set, use it instead of the record value
				if(gr_task_pref.u_servicenow_form_view && gr_task_pref.u_servicenow_form_view != ''){
					url_Properties.view = task_default_form_view.sn_view;
				}
				// this is second, so it overrides the view above
				if(formToLoad.u_servicenow_form_view.displayValue != '' && formToLoad.u_servicenow_form_view.displayValue != null){
					url_Properties.view = formToLoad.u_servicenow_form_view.value;
				}

			// STRY0119569
			} else if(gr_task_pref.getDisplayValue("u_servicenow_form_view") != ""){
				// if there is no form override, and the view is set for the task, set the view for the task based on the user selection
				url_Properties.view = task_default_form_view.sn_view;	
			}
		}
		return url_Properties;
	},

	// DFCT0010708
	get_URL_Properties_for_Task_Based_on_Prefrences: function(sys_id, current_view){
		var currentUserId = gs.getUserID();
		return this.get_URL_Properties_for_Task_and_User_Based_on_Prefrences (currentUserId, sys_id, current_view);
	},


	// DFCT0010708
	getEmailLink: function(currentTask){
		//create a task link using form preferences and the current sys_id
		var task_url = this.getEmailUrl(currentTask);

		// TODO, NEED TO TAKE STYLING OUT OF HERE!
		var task_link = "<span style='font-family: georgia, palatino; font-size: 12pt;'><a href='" + task_url + "'>" + 
			currentTask.number + " - " + currentTask.task_name +
			"</a></span>";
		return task_link;

	},
	// DFCT0010708
	getEmailUrl: function(currentTask){
		// check for assigned member
		var userID = currentTask.getValue('assigned_to') + '';
		if(userID == ''){
			// check for Task Onwer
			userID = currentTask.getValue('u_task_requester') + '';
		}
		if(userID == ''){
			// use originator
			userID = currentTask.getValue('originator') + '';
		}
		var userPreferences =  this.loadUserFormPreferences(userID);
		var url_Properties = this.get_URL_Properties_for_Task_and_User_Based_on_Prefrences(userID, currentTask.getUniqueValue(),'sp');

		var pageId = url_Properties.pageId && url_Properties.pageId != '' ? url_Properties.pageId : 'discovertasker_taskdetails';
		var view = url_Properties.view && url_Properties.view != '' ? url_Properties.view : 'sp';

		//create a task link using form preferences and the current sys_id
		return task_url = url_Properties.portal_url_ref + '?sys_id='+ currentTask.sys_id +'&view=' + view + '&id=' + pageId + '&table=x_153465_discovert_route_task_instance';

	},

    type: 'tasker_User_Form_Preferences'
};
